    31→/// Returns an `ArrayAttr` where each element is an `IntegerAttr` of 64-bit
    32→/// integer type whose values is obtained from `values`.
    33→static ArrayAttr getIndexArrayAttr(MLIRContext *context,
    34→                                   ArrayRef<int64_t> values) {
    35→  return ArrayAttr::get(
    36→      context, llvm::map_to_vector(values, [&](int64_t value) -> Attribute {
    37→        return IntegerAttr::get(IndexType::get(context), APInt(64, value));
    38→      }));
    39→}
