    91→LogicalResult TranslationInfoAttr::verify(
    92→    function_ref<InFlightDiagnostic()> emitError,
    93→    IREE::Codegen::DispatchLoweringPassPipelineAttr passPipeline,
    94→    SymbolRefAttr codegenSpec, ArrayRef<int64_t> workgroupSize,
    95→    int64_t subgroupSize, DictionaryAttr configuration) {
    96→  if (!passPipeline) {
    97→    return emitError() << "missing pass pipeline specification";
    98→  }
    99→  auto passPipelineValue = passPipeline.getValue();
   100→  if (passPipelineValue > IREE::Codegen::DispatchLoweringPassPipeline::None) {
   101→    return emitError() << "invalid pass pipeline value : "
   102→                       << stringifyEnum(passPipeline.getValue());
   103→  }
   104→  auto tdPassPipeline =
   105→      IREE::Codegen::DispatchLoweringPassPipeline::TransformDialectCodegen;
   106→  if (codegenSpec && passPipelineValue != tdPassPipeline) {
   107→    return emitError()
   108→           << "transform dialect codegen spec requires pass pipeline : "
   109→           << stringifyEnum(tdPassPipeline);
   110→  }
   111→  if (workgroupSize.size() > 3) {
   112→    return emitError() << "workgroup size cannot have more than 3 entries";
   113→  }
   114→  if (llvm::any_of(workgroupSize, [](int64_t value) { return value <= 0; })) {
   115→    return emitError() << "workgroup size value has to be greater than zero";
   116→  }
   117→  if (subgroupSize < 0) {
   118→    return emitError() << "subgroup size value cannot be negative";
   119→  }
   120→  return success();
   121→}
